mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM pq_product
    WHERE product_code = #{productCode}
)

mapper.insert:
INSERT INTO pq_product (
    product_code,
    product_model,
    status
) VALUES (
    #{productCode},
    #{productModel},
    #{status}
)

mapper.update:
UPDATE pq_product
SET product_model = #{productModel}
WHERE id = #{id}

UPDATE pq_product
SET status = #{status}
WHERE id = #{id}
